import React, { useState, useEffect } from 'react'
import { Link } from 'react-router-dom';
import { API_KEY, POSTER_PATH, WIDTH_200, API_TV } from '../constant';
import { LazyLoadImage } from 'react-lazy-load-image-component';

const Season = (props) => {
  const { id } = props;
  const [data, setData] = useState([]);

  useEffect(() => {
    const getData = async () => {
      await fetch(API_TV + id + '?api_key=' + API_KEY)
        .then((response) => {
          return response.json();
        })
        .then((data) => {
          setData(data.seasons);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [id]);

  return (
    <div className="mt-5">
      <h2>Episodes</h2>
      <div className="d-flex flex-row">
        {data.map((dataRow, index) => (
          <Link key={index} className="card-link" to={'/tv/'+ id + '/season/' + dataRow.season_number}>
            <div className="card frameWidth" key={index}>
              <LazyLoadImage className="card-img-top" src={POSTER_PATH + WIDTH_200 + dataRow.poster_path} effect="opacity" alt={dataRow.title ? dataRow.title : dataRow.name} onError={(e)=>{e.target.onerror = null; e.target.src="https://fakeimg.pl/200x300?text=MoviesHub&font=bebas&font_size=35"}} />
              <div className="card-body">
                <div className="card-text">
                  <div>{(`${dataRow.air_date}`).substring(0, 4) !== 'unde' ? (`${dataRow.air_date}`).substring(0, 4) : 'Date not defined'}</div>
                  <div className="text-bold">{dataRow.title ? dataRow.title : dataRow.name}</div>
                  <div className="text-muted">{dataRow.episode_count} edpisodes</div>
                </div>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </div>
  )
}

export default Season
